const date = $('Execute Workflow Trigger').first().json.date;
const items = $input.all();

if (!items || items.length === 0 || !items[0].json.Hora) {
  return [{ json: { date, occupied: [], message: `El dia ${date} no tiene turnos ocupados. Todos los horarios de 9:00 a 18:00 estan disponibles.` } }];
}

const occupied = items
  .filter(i => i.json.Hora)
  .map(i => i.json.Hora)
  .sort();

const allSlots = ['09:00','09:30','10:00','10:30','11:00','11:30','12:00','12:30','14:00','14:30','15:00','15:30','16:00','16:30','17:00','17:30'];
const available = allSlots.filter(s => !occupied.includes(s));

return [{ json: {
  date,
  occupied,
  available,
  message: `Para el ${date}: Ocupados: ${occupied.join(', ') || 'ninguno'}. Disponibles: ${available.join(', ')}.`
}}];
